sql:
SELECT gardener_name
FROM gardeners
WHERE location_id = 1;

SELECT cycle_id
FROM plant_growth_cycles
WHERE location_id = 1;

SELECT cycle_id 
FROM plant_growth_cycles 
ORDER BY cycle_id;

SELECT COUNT(*) AS observation_count
FROM plant_observations
WHERE cycle_id = 0;

SELECT cycle_id, plant_id, location_id, start_date, end_date
FROM plant_growth_cycles
WHERE growth_conditions = 'Very Hot';

SELECT harvest_quantity
FROM plant_harvests
WHERE harvest_quality = 'Excellent';

SELECT DISTINCT gardener_id
FROM plant_maintenance
ORDER BY gardener_id;
